insert into public.roast_lines (kind, category, level, wave, tactic, bucket, text) values
  ('wave', 'gym', 4, 4, 'roast', null, 'The gym was open all day and you knew it. It was open when you woke up, open at lunch, and it''s still open right now while you decide you''re too tired. Twelve hours, zero used.'),
  ('wave', 'gym', 4, 4, 'roast', null, 'You didn''t go to the gym again. The shoes are by the door where you left them this morning, and they''ve done more standing around today than you have.'),
  ('wave', 'gym', 4, 4, 'roast', null, 'Another workout skipped, another day the plan survives only in your head. You''ve been "starting properly on Monday" since sometime around March.'),
  ('wave', 'gym', 4, 4, 'roast', null, 'You bought the whole gym outfit and it''s still folded in the drawer. At this rate it''ll wear out from being looked at before it ever sees a treadmill.'),
  ('wave', 'gym', 4, 4, 'roast', null, 'You''ve talked about the gym more than you''ll ever actually go. If describing a workout burned calories you''d be in great shape by now.'),
  ('wave', 'gym', 4, 4, 'roast', null, 'The pre-workout kicked in and you spent every bit of that energy scrolling on the couch. That was the session. That was the whole thing.'),
  ('wave', 'gym', 4, 4, 'roast', null, 'You called one flight of stairs "leg day" and for a second I thought you were joking. You were not.'),
  ('wave', 'gym', 4, 4, 'roast', null, 'Your gym bag has been packed by the front door for three days. It''s not a decoration, and you walk past it anyway like it is.'),
  ('wave', 'gym', 4, 4, 'roast', null, 'You said you''d go after work, then after dinner, then "tomorrow for sure." It''s tomorrow now. You already know how this ends.'),
  ('wave', 'gym', 4, 4, 'roast', null, 'The membership charges you whether you show up or not, and lately it''s basically a monthly donation. Very generous of you.'),
  ('wave', 'study', 4, 4, 'roast', null, 'You made a study plan last week and never touched it. Today you sat down and made a brand new plan instead of doing the old one. The planning is the actual hobby at this point.'),
  ('wave', 'study', 4, 4, 'roast', null, 'The textbook is open to the same page it''s been on since Tuesday. You''ve looked at it, taken a photo of it for your story, and closed it again.'),
  ('wave', 'study', 4, 4, 'roast', null, 'You''ve watched forty minutes of "study with me" videos instead of studying. Someone else is being productive on camera and you''re calling that research.'),
  ('wave', 'study', 4, 4, 'roast', null, 'You reorganized your desk, color-coded your notes, and bought new highlighters. None of that is studying, and I''m fairly sure you know that.'),
  ('wave', 'study', 4, 4, 'roast', null, 'You said you "work better under pressure," which is a generous way of saying you haven''t started and won''t until it''s an emergency.'),
  ('wave', 'study', 4, 4, 'roast', null, 'The notes look great. Clean, organized, and completely unread. You built a museum exhibit out of information you''re actually supposed to learn.'),
  ('wave', 'study', 4, 4, 'roast', null, 'You opened the material, decided to "review it quickly," and ended up arguing with a stranger online for an hour. Solid session.'),
  ('wave', 'study', 4, 4, 'roast', null, 'You know every detail about your favorite creator''s life and not one line from {name}. Interesting priorities for someone with an exam coming up.'),
  ('wave', 'study', 4, 4, 'roast', null, 'The flashcards you made in September are still in the shrink wrap. You spent more time making them than you''ll ever spend using them.'),
  ('wave', 'study', 4, 4, 'roast', null, 'You''ll cram the night before, blame the professor when it goes badly, and swear next time is different. It won''t be, but I do admire the consistency.'),
  ('wave', 'chores', 4, 4, 'roast', null, '{name} takes ten minutes and you''ve spent a week avoiding it. You''ve walked past it so many times it''s basically part of the furniture now.'),
  ('wave', 'chores', 4, 4, 'roast', null, 'The dishes have been sitting there long enough to develop a personality. You keep adding to the pile like that''s a form of progress.'),
  ('wave', 'chores', 4, 4, 'roast', null, 'You lit a candle so the place would "feel clean," which is bold for someone who hasn''t cleaned anything. The mess is still there. It just smells nicer now.'),
  ('wave', 'chores', 4, 4, 'roast', null, 'You said you''d do it after this one episode. That was six episodes ago and the laundry hasn''t moved an inch.'),
  ('wave', 'chores', 4, 4, 'roast', null, 'You''d rather deep-clean your phone screen than touch the pile by {cue}. Real dedication to doing anything except the actual thing.'),
  ('wave', 'chores', 4, 4, 'roast', null, '{cue} is sitting exactly where it was three days ago. It isn''t going to move on its own, no matter how long you stare at it.'),
  ('wave', 'chores', 4, 4, 'roast', null, 'Company''s coming over and suddenly you''re a cleaning machine. Funny how the mess was invisible right up until someone else might see it.'),
  ('wave', 'chores', 4, 4, 'roast', null, 'You''ve "been meaning to get to it" so long that "it" is now a permanent fixture. At this point the mess practically pays rent.'),
  ('wave', 'chores', 4, 4, 'roast', null, 'You tidied by moving one thing two feet to the left and sitting back down. That''s not cleaning, that''s just rearranging the scene.'),
  ('wave', 'chores', 4, 4, 'roast', null, 'The chore list has the same three items it had on Monday. You keep looking at it like reading it counts as doing it.'),
  ('wave', 'diet', 4, 4, 'roast', null, 'The diet lasted until lunch, same as last time and the time before that. By noon you''d already talked yourself into "starting fresh tomorrow."'),
  ('wave', 'diet', 4, 4, 'roast', null, 'You meal-prepped a whole fridge of containers and ordered takeout twice anyway. The containers are just sitting there watching. They know.'),
  ('wave', 'diet', 4, 4, 'roast', null, 'You called it a cheat day again. It''s the fourth one this week, which means the cheat is the plan and the diet is the exception.'),
  ('wave', 'diet', 4, 4, 'roast', null, 'You spent ten minutes reading the healthy options and then ordered your usual, like you always do. The research was purely for show.'),
  ('wave', 'diet', 4, 4, 'roast', null, 'You "eat clean" when people are watching and raid the fridge at 11pm when they''re not. I see both shifts. I don''t have anywhere else to be.'),
  ('wave', 'diet', 4, 4, 'roast', null, 'One bite turned into the whole thing again. It always does, and you always look surprised, like it hasn''t gone exactly this way every single time.'),
  ('wave', 'diet', 4, 4, 'roast', null, 'The salad is wilting in the fridge while you finish the fries. You bought it with good intentions and precisely zero follow-through.'),
  ('wave', 'diet', 4, 4, 'roast', null, 'You''ve said "starts Monday" so many times that Mondays have stopped taking you seriously. Today was a Monday, for what it''s worth.'),
  ('wave', 'diet', 4, 4, 'roast', null, 'You''re counting a "small" portion like the numbers care how you label it. The amount is the amount, whatever you decide to call it.'),
  ('wave', 'diet', 4, 4, 'roast', null, 'You blamed the weekend for the diet falling apart, as if the weekend reached over and fed you itself. That part was all you.'),
  ('wave', 'water', 4, 4, 'roast', null, 'You''ve had three coffees and not one glass of water. Then you''ll wonder why your head hurts at 3pm, like it''s some great mystery instead of the obvious answer.'),
  ('wave', 'water', 4, 4, 'roast', null, 'The water bottle has followed you around all day, full and untouched. You''ve carried it everywhere except to your mouth.'),
  ('wave', 'water', 4, 4, 'roast', null, '{name} is the easiest goal you''ve got and you''re still ignoring it. All you have to do is drink. That is the entire task.'),
  ('wave', 'water', 4, 4, 'roast', null, 'Your houseplant drinks more consistently than you do, and it can''t even reach the sink. Sit with that one for a second.'),
  ('wave', 'water', 4, 4, 'roast', null, 'You''ll drink coffee, soda, and energy drinks all day, but the one thing on the list gets skipped every single time.'),
  ('wave', 'water', 4, 4, 'roast', null, 'Two sips by 4pm is not the hydration plan you think it is. The bottle is right there and has been the whole time.'),
  ('wave', 'water', 4, 4, 'roast', null, 'You set a reminder to drink water, swiped it away without a thought, and complained about being tired an hour later. Connect the two.'),
  ('wave', 'water', 4, 4, 'roast', null, '"I forgot to drink water" is a wild thing to say about a bottle sitting six inches from your hand all day. You didn''t forget. You ignored it.'),
  ('wave', 'water', 4, 4, 'roast', null, 'The headache showed up right on schedule and you still didn''t take the hint. The signals keep coming and you keep marking them unread.'),
  ('wave', 'water', 4, 4, 'roast', null, 'You treat water like an optional extra and then act confused about why you feel rough by evening. It isn''t a puzzle. Drink the water.'),
  ('wave', 'sleep', 4, 4, 'roast', null, '{name} means nothing while you''re up at 1am watching strangers argue about nothing online. You set a bedtime and treat it like a suggestion someone else made.'),
  ('wave', 'sleep', 4, 4, 'roast', null, 'You said "one more episode" three episodes ago. You knew it was a lie when you said it, and so did I.'),
  ('wave', 'sleep', 4, 4, 'roast', null, 'You doomscroll until 2am and then act shocked when the morning is hard. The morning didn''t change. You did that to yourself last night.'),
  ('wave', 'sleep', 4, 4, 'roast', null, 'The second the lights go off, your brain decides now is the perfect time to start a whole new project. Very convenient, and completely fake.'),
  ('wave', 'sleep', 4, 4, 'roast', null, 'You set an alarm to fix your sleep and then stayed up late enough to turn that alarm into your enemy. You''re losing a war you started.'),
  ('wave', 'sleep', 4, 4, 'roast', null, 'The phone is the last thing you look at every single night, and then you wonder why your sleep is a mess. It isn''t a mystery.'),
  ('wave', 'sleep', 4, 4, 'roast', null, 'You told someone you were "going to bed" an hour ago and you''re still very much awake. Apparently going to bed means lying down and staying online.'),
  ('wave', 'sleep', 4, 4, 'roast', null, 'Your bedtime has more plot twists than the shows keeping you up. It slides later every night and you keep pretending that isn''t a pattern.'),
  ('wave', 'sleep', 4, 4, 'roast', null, '"I''ll sleep when I''m dead" is fun to say right up until it''s 4am and you''re staring at the ceiling regretting it. Tonight could be different. It won''t be.'),
  ('wave', 'sleep', 4, 4, 'roast', null, 'You''ll "rest your eyes" for a minute and wake up at 4am fully dressed with the lights still on. That''s not resting, that''s just powering off on the couch.'),
  ('wave', 'custom', 4, 4, 'roast', null, '{name} is something you say to feel productive, not something you actually do. You set it, you look at it, and then you go do literally anything else.'),
  ('wave', 'custom', 4, 4, 'roast', null, 'You''ve planned {name} more times than you''ve done it, and it isn''t close. The planning feels like progress, which is exactly why nothing gets finished.'),
  ('wave', 'custom', 4, 4, 'roast', null, 'You''re reading this right now instead of doing {name}, which is honestly the most on-brand thing you could be doing.'),
  ('wave', 'custom', 4, 4, 'roast', null, 'You set {cue} as a reminder and developed instant amnesia the second you saw it. It''s not that you forgot. You decided not to.'),
  ('wave', 'custom', 4, 4, 'roast', null, '{name} again? We both already know how this goes. You''ll think about it, feel a little bad about it, and do nothing about it.'),
  ('wave', 'custom', 4, 4, 'roast', null, 'You talk a big game about {name} and then deliver absolutely nothing. All setup, no follow-through, every single time.'),
  ('wave', 'custom', 4, 4, 'roast', null, '{name} has been "in progress" long enough to collect dust. Nothing has actually happened, but you keep the label on it so it feels alive.'),
  ('wave', 'custom', 4, 4, 'roast', null, 'You keep waiting for motivation to show up before you start, like it owes you a visit. It doesn''t, it won''t, and you''ll use that as the excuse.'),
  ('wave', 'custom', 4, 4, 'roast', null, 'You set the reminder for {name} mostly so you could feel the small thrill of ignoring it. Congratulations on building a system that works perfectly against you.'),
  ('wave', 'custom', 4, 4, 'roast', null, 'Tomorrow''s your big fresh start for {name}, same as yesterday''s was, and the day before that. At some point "tomorrow" is just the word you use to avoid today.'),
  ('skip', null, 4, null, null, null, 'So your reason today is "{excuse}." You said the same thing on Monday, and again on Wednesday, and I believed it a little less each time. This was never really about {excuse}.'),
  ('skip', null, 4, null, null, null, '"{excuse}," sure. That would land better if your screen time didn''t show two hours of scrolling right before you decided you were too busy.'),
  ('skip', null, 4, null, null, null, 'You typed "{excuse}" with a straight face, which takes real confidence given how many times you''ve used it this week. At least mix it up.'),
  ('skip', null, 4, null, null, null, '"{excuse}" again. It was believable the first couple of times. Now it''s just the button you press to make the guilt go away for a minute.'),
  ('skip', null, 4, null, null, null, 'Your excuse is "{excuse}," and the funny part is you had time for everything else today. Just not this. Never this.'),
  ('skip', null, 4, null, null, null, '"{excuse}" is doing an enormous amount of work for someone who''s done none. I''d honestly respect a flat "I don''t feel like it" more.'),
  ('skip', null, 4, null, null, null, 'So we''re going with "{excuse}." Noted and logged. We both know what it actually means, but I''ll write down the polite version for the record.'),
  ('skip', null, 4, null, null, null, '"{excuse}" shows up like clockwork the exact moment it''s time to do the thing. Strange how it never turns up at any other point in the day.'),
  ('skip', null, 4, null, null, null, 'You said "{excuse}" and hit skip before the countdown even finished. That''s not a reason, that''s a reflex, and we both know it.'),
  ('skip', null, 4, null, null, null, 'Impressive commitment to "{excuse}" as your answer for the third day in a row. You could at least rotate the material.'),
  ('digest', null, 4, null, null, null, 'You''ve got {count} things due today. Realistically you''ll knock out the easiest one, feel accomplished for an hour, and let the rest slide into tomorrow. We''ve seen this before.'),
  ('digest', null, 4, null, null, null, '{count} goals due and the day already has a plan: do the bare minimum, then decide the rest can wait. It usually can''t, but that''s never stopped you.'),
  ('digest', null, 4, null, null, null, 'There are {count} things on your list today. Odds are you''ll spend more energy avoiding them than it would take to just do them.'),
  ('digest', null, 4, null, null, null, '{count} due today. You''ll look at the list, feel a brief wave of motivation, and then find something else to do for the next four hours.'),
  ('digest', null, 4, null, null, null, 'You set {count} goals for today, which is ambitious for someone about to ignore most of them. Bold to schedule this much disappointment in advance.'),
  ('digest', null, 4, null, null, null, '{count} things due and you''re already tired just from reading them. That''s the tell. You decided the outcome before the day even started.'),
  ('digest', null, 4, null, null, null, 'Today''s list has {count} items. History says one gets done, maybe, and the rest quietly roll onto tomorrow''s list to be ignored again.'),
  ('digest', null, 4, null, null, null, '{count} goals waiting on you today. You''ll get to them right after you check your phone one more time, which will somehow eat the whole morning.'),
  ('digest', null, 4, null, null, null, 'You''ve got {count} due. The easy money says you do the fun one, skip the hard ones, and tell yourself tomorrow is the real start.'),
  ('digest', null, 4, null, null, null, '{count} things to handle today, and we both know your effort budget for this is running close to zero. Prove me wrong. You won''t, but you could.'),
  ('partial', 'gym', 4, null, null, 'low', '{done} {unit} out of {target}. That''s not a workout, that''s standing up with extra steps. You quit before your heart rate even noticed.'),
  ('partial', 'gym', 4, null, null, 'low', '{done} {unit} out of {target} at the gym. You basically showed up just to prove you could leave early.'),
  ('partial', 'gym', 4, null, null, 'half', '{done} {unit} out of {target} and you racked it. You did the half that''s easy and skipped the half that actually changes anything.'),
  ('partial', 'gym', 4, null, null, 'half', '{done} out of {target} {unit} and you clocked out right when it started to work.'),
  ('partial', 'gym', 4, null, null, 'almost', '{done} {unit} out of {target} and you stopped. So close, and you handed it right back.'),
  ('partial', 'gym', 4, null, null, 'almost', '{done} out of {target} {unit}. You could see the cooldown from there and sat down instead.'),
  ('partial', 'study', 4, null, null, 'low', '{done} {unit} out of {target}. I thought that was a typo. It was not. You opened the book and immediately closed the deal on doing nothing.'),
  ('partial', 'study', 4, null, null, 'low', 'You read {done} {unit} of {target} and logged it like it counts. That''s signing the attendance sheet and going home.'),
  ('partial', 'study', 4, null, null, 'half', '{done} {unit} out of {target}. You did the easy half and stopped right before the part that shows up on the exam.'),
  ('partial', 'study', 4, null, null, 'half', 'Halfway, {done} of {target} {unit}, and then your focus wandered off and never came back.'),
  ('partial', 'study', 4, null, null, 'almost', '{done} {unit} out of {target} and you quit. You were basically done and still found a way not to finish.'),
  ('partial', 'study', 4, null, null, 'almost', '{done} of {target} {unit}. The end was right there and you closed the book on principle, apparently.'),
  ('partial', 'chores', 4, null, null, 'low', '{done} {unit} out of {target}. You picked up one thing, felt the effort, and sat back down.'),
  ('partial', 'chores', 4, null, null, 'low', 'You did {done} {unit} out of {target} and called it tidying. That''s rearranging the mess, not clearing it.'),
  ('partial', 'chores', 4, null, null, 'half', '{done} {unit} out of {target} and you stopped. Half-cleaned is just a mess with better lighting.'),
  ('partial', 'chores', 4, null, null, 'half', 'Halfway through the {target} {unit}, and then you found something more interesting to not do.'),
  ('partial', 'chores', 4, null, null, 'almost', '{done} {unit} out of {target} and you bailed. A couple steps from done and you walked away from the finish.'),
  ('partial', 'chores', 4, null, null, 'almost', '{done} of {target} {unit}. Almost the whole thing, and you still left the last corner untouched.'),
  ('partial', 'diet', 4, null, null, 'low', '{done} {unit} out of {target} today. You had the intention, and then the snack drawer had you.'),
  ('partial', 'diet', 4, null, null, 'low', 'You hit {done} of {target} {unit}. The rest were "starting tomorrow" in disguise.'),
  ('partial', 'diet', 4, null, null, 'half', '{done} of {target} {unit} and then the weekend logic kicked in early. Half a plan is no plan by dinner.'),
  ('partial', 'diet', 4, null, null, 'half', 'Halfway to {target} {unit} and you tapped out at {done}. The easy half, naturally.'),
  ('partial', 'diet', 4, null, null, 'almost', '{done} of {target} {unit} and you fumbled the last one at midnight. So close, and then the fridge won.'),
  ('partial', 'diet', 4, null, null, 'almost', '{done} out of {target} {unit} and the final stretch undid the whole day. You were almost through and you knew it.'),
  ('partial', 'water', 4, null, null, 'low', '{done} {unit} out of {target}. That''s not hydration, that''s a rumor of it. The bottle is right there and still full.'),
  ('partial', 'water', 4, null, null, 'low', 'You drank {done} {unit} of {target} today. Then the headache showed up right on cue and you acted surprised.'),
  ('partial', 'water', 4, null, null, 'half', '{done} {unit} out of {target} and you stopped. Halfway hydrated is still walking around tired by 4pm.'),
  ('partial', 'water', 4, null, null, 'half', 'Halfway to {target} {unit}, and then the bottle sat untouched for the rest of the day.'),
  ('partial', 'water', 4, null, null, 'almost', '{done} {unit} of {target} and you quit at the last sip. You were basically there and left it in the bottle.'),
  ('partial', 'water', 4, null, null, 'almost', '{done} out of {target} {unit}. One glass from done and you called it. Why.'),
  ('partial', 'sleep', 4, null, null, 'low', '{done} {unit} out of {target}. You didn''t sleep, you took a nap and called it a night.'),
  ('partial', 'sleep', 4, null, null, 'low', '{done} of {target} {unit} because "one more episode" turned into five. Tomorrow''s going to be rough and you built it yourself.'),
  ('partial', 'sleep', 4, null, null, 'half', '{done} {unit} out of {target} and the phone got the rest. Half a night''s sleep and a full day of regretting it.'),
  ('partial', 'sleep', 4, null, null, 'half', 'Halfway to {target} {unit}, and then 2am found you wide awake again.'),
  ('partial', 'sleep', 4, null, null, 'almost', '{done} {unit} out of {target} and you cut it short scrolling. So close to a full night, and you gave the last hour to your phone.'),
  ('partial', 'sleep', 4, null, null, 'almost', '{done} of {target} {unit}. Almost a real night''s sleep and you traded the end of it for nothing.'),
  ('partial', 'custom', 4, null, null, 'low', '{done} {unit} out of {target} and then you stopped. You did just enough to say you started and not one bit more.'),
  ('partial', 'custom', 4, null, null, 'low', 'You logged {done} of {target} {unit} and want credit for it. That''s the effort version of showing up late and leaving early.'),
  ('partial', 'custom', 4, null, null, 'half', '{done} {unit} out of {target} and you folded at the midpoint. Half is exactly where you always quit, so at least it''s on brand.'),
  ('partial', 'custom', 4, null, null, 'half', 'Halfway there, {done} of {target} {unit}, and then your motivation quietly filed out of the room.'),
  ('partial', 'custom', 4, null, null, 'almost', '{done} {unit} out of {target} and you tapped out. Two away from done and you handed it back at the buzzer.'),
  ('partial', 'custom', 4, null, null, 'almost', '{done} of {target} {unit}. You did all the hard part and quit right before it counted. That''s the part I don''t get.'),
  ('weekly', 'gym', 4, null, null, 'low', 'You wanted the gym {target} times this week and you''ve gone {done}. It''s not looking like a comeback from here.'),
  ('weekly', 'gym', 4, null, null, 'low', '{done} gym days out of {target} this week. At this pace the plan quietly becomes next week''s plan.'),
  ('weekly', 'gym', 4, null, null, 'half', 'Halfway to your {target} gym days with {done} done. The back half of the week is where this usually falls apart.'),
  ('weekly', 'gym', 4, null, null, 'half', '{done} of {target} gym days in. You''re right on the line between on track and the story you''ll tell yourself Sunday.'),
  ('weekly', 'gym', 4, null, null, 'almost', '{done} of {target} gym days, one short. You''re close enough that skipping now would be a genuine waste.'),
  ('weekly', 'gym', 4, null, null, 'almost', 'Almost there, {done} of {target} gym days. Don''t let the last one turn into "I basically did it."'),
  ('weekly', 'study', 4, null, null, 'low', 'You aimed for {target} study days this week and hit {done}. The exam isn''t going to move to match your pace.'),
  ('weekly', 'study', 4, null, null, 'low', '{done} of {target} study sessions this week. The other days you meant to, which counts for nothing.'),
  ('weekly', 'study', 4, null, null, 'half', 'Halfway to {target} study days with {done} done. You know the second half of the week is where you always fade.'),
  ('weekly', 'study', 4, null, null, 'half', '{done} of {target} study days in. On track for now, which is not the same as finished.'),
  ('weekly', 'study', 4, null, null, 'almost', '{done} of {target} study days, one to go. You''ve done the hard part, so don''t fumble the easy one.'),
  ('weekly', 'study', 4, null, null, 'almost', 'Almost at your {target} study days, {done} down. Stopping here would be a strange place to quit.'),
  ('weekly', 'chores', 4, null, null, 'low', 'You planned {target} clean-ups this week and managed {done}. The mess doesn''t care about your intentions.'),
  ('weekly', 'chores', 4, null, null, 'low', '{done} of {target} chore days this week. The rest of the list is still exactly where you left it.'),
  ('weekly', 'chores', 4, null, null, 'half', 'Halfway to {target} chore days with {done} done. The weekend version of you is not known for finishing this.'),
  ('weekly', 'chores', 4, null, null, 'half', '{done} of {target} chore days in. Fine so far, but so far has burned you before.'),
  ('weekly', 'chores', 4, null, null, 'almost', '{done} of {target} chore days, one left. You''re too close to let it roll into next week.'),
  ('weekly', 'chores', 4, null, null, 'almost', 'Almost done, {done} of {target} chore days. Don''t stall out on the final one.'),
  ('weekly', 'diet', 4, null, null, 'low', 'You wanted {target} on-plan days and you''ve had {done}. The week is basically writing its own ending already.'),
  ('weekly', 'diet', 4, null, null, 'low', '{done} of {target} clean days this week. The other days had opinions and the snack drawer won.'),
  ('weekly', 'diet', 4, null, null, 'half', 'Halfway to {target} clean days with {done} done. The weekend is coming and it has never been your friend here.'),
  ('weekly', 'diet', 4, null, null, 'half', '{done} of {target} on-plan days in. Holding for now, which the weekend tends to fix.'),
  ('weekly', 'diet', 4, null, null, 'almost', '{done} of {target} clean days, one short. This is a bad week to cave right at the finish.'),
  ('weekly', 'diet', 4, null, null, 'almost', 'Almost at {target} clean days, {done} down. One more and you actually pull it off for once.'),
  ('weekly', 'water', 4, null, null, 'low', 'You aimed for {target} days of hitting your water and hit {done}. The bottle''s available all seven, for the record.'),
  ('weekly', 'water', 4, null, null, 'low', '{done} of {target} water days this week. The other days you just decided thirst was a personality.'),
  ('weekly', 'water', 4, null, null, 'half', 'Halfway to {target} water days with {done} done. Somehow this is the goal you still find hard.'),
